import { AccountAddress } from '@aptos-labs/ts-sdk';
import { z } from 'zod';
import { b as ClayConfig } from '../clay-codes-DHP-bYcP.js';
import '@shelby-protocol/clay-codes';

declare const BlobNameSchema: z.ZodEffects<z.ZodString, string, string>;
type BlobName = z.infer<typeof BlobNameSchema>;
/**
 * Describes a chunk in the system. This key is unique in the system modulo some assumptions
 * about time, specifically surrounding deletion. The same key cannot exist
 * twice in the system, so anything interacting with metadata must clear out old
 * versions of this key and posible recreate them in the right order.
 *
 * This ends up being an on-chain structure as well.
 */
declare class ChunkKey {
    readonly account: AccountAddress;
    readonly blobName: string;
    readonly chunksetIdx: number;
    readonly chunkIdx: number;
    readonly config: ClayConfig;
    constructor(account: AccountAddress, blobName: string, chunksetIdx: number, chunkIdx: number, config: ClayConfig);
    key(): string;
    range(): {
        start: number;
        end: number;
    } | "parity";
}

export { type BlobName, BlobNameSchema, ChunkKey };
